mapper.select:
SELECT * FROM (
SELECT ROWNUM AS rn, a.* FROM (
SELECT s.*, COUNT(*) OVER() AS total_cnt
FROM SUPPORT s
WHERE 1=1

    AND REG_NO = #{filterRegNo}


    AND SUP_YN = #{supYn}

ORDER BY SUP_NO DESC
) a
WHERE ROWNUM <= #{pageNo} * #{pageSize}
)
WHERE rn > (#{pageNo} - 1) * #{pageSize}

mapper.update:
UPDATE SUPPORT
SET SUP_ANS_CN     = #{supAnsCn},
    SUP_ANS_REG    = TO_CHAR(SYSDATE, 'YYYYMMDD'),
    SUP_ANS_REG_HM = TO_CHAR(SYSDATE, 'HH24MI'),
    SUP_YN         = #{supYn}
WHERE SUP_NO = #{supNo}

